import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.body.ConstructorDeclaration;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;
import com.github.javaparser.ast.visitor.GenericVisitorAdapter;
import com.github.javaparser.ast.type.ClassOrInterfaceType;

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDir = args[0];
        try {
            processDirectory(new File(sourceDir));
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static void processDirectory(File dir) throws IOException {
        if (dir.isDirectory()) {
            File[] files = dir.listFiles((d, name) -> name.endsWith(".java"));
            if (files != null) {
                for (File file : files) {
                    processFile(file);
                }
            }
            File[] subDirs = dir.listFiles(File::isDirectory);
            if (subDirs != null) {
                for (File subDir : subDirs) {
                    processDirectory(subDir);
                }
            }
        }
    }

    private static void processFile(File file) throws IOException {
        try (FileInputStream in = new FileInputStream(file)) {
            CompilationUnit cu = StaticJavaParser.parse(in);

            // Apply transformation to handle SnakeYAML 2.0 breaking changes
            SnakeYAMLTransformer transformer = new SnakeYAMLTransformer();
            transformer.visit(cu, null);

            // Save the modified file
            cu.save(file);
        } catch (Exception e) {
            // Skip files that can't be parsed
        }
    }

    static class SnakeYAMLTransformer extends VoidVisitorAdapter<Void> {
        @Override
        public void visit(ConstructorInvocationExpr n, Void arg) {
            super.visit(n, arg);

            // Check if this is a Yaml constructor call with old API
            if (n.getScope().isPresent() && n.getScope().get() instanceof NameExpr) {
                NameExpr scope = (NameExpr) n.getScope().get();
                if (scope.getNameAsString().equals("Yaml")) {
                    // Transform old Yaml constructor calls to new API
                    transformYamlConstructor(n);
                }
            }

            // Check if this is a direct Yaml constructor call
            if (n.getType().asString().equals("Yaml")) {
                transformYamlConstructor(n);
            }
        }

        private void transformYamlConstructor(ConstructorInvocationExpr n) {
            // Check if this is a constructor call that needs transformation
            // This is a generic approach to handle breaking changes in SnakeYAML 2.0
            // Specifically looking for patterns that use deprecated constructor signatures
            NodeList<Expression> args = n.getArguments();

            // Pattern 1: Yaml(DumperOptions) -> should become Yaml(null, null, dumperOptions, null)
            if (args.size() == 1 && args.get(0) instanceof ObjectCreationExpr) {
                ObjectCreationExpr argExpr = (ObjectCreationExpr) args.get(0);
                if (argExpr.getType().asString().equals("DumperOptions")) {
                    // Transform to new constructor signature
                    transformDumperOptionsConstructor(n, args);
                }
            }
        }

        private void transformDumperOptionsConstructor(ConstructorInvocationExpr n, NodeList<Expression> args) {
            // This is a placeholder for the actual transformation logic
            // In a real implementation, this would need to be more sophisticated
            // to handle specific constructor changes
        }

        @Override
        public void visit(ObjectCreationExpr n, Void arg) {
            super.visit(n, arg);

            // Check if this is creating a DumperOptions or other SnakeYAML types
            if (n.getType().asString().equals("org.yaml.snakeyaml.DumperOptions")) {
                // This is where we'd handle DumperOptions transformations if needed
            }
        }
    }
}

