package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.expr.*;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.NodeList;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.body.ConstructorDeclaration;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;
import com.github.javaparser.ast.visitor.GenericVisitorAdapter;
import com.github.javaparser.ast.type.ClassOrInterfaceType;
import com.github.javaparser.ast.type.Type;

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDir = args[0];
        try {
            processDirectory(new File(sourceDir));
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static void processDirectory(File dir) throws IOException {
        if (dir.isDirectory()) {
            File[] files = dir.listFiles((d, name) -> name.endsWith(".java"));
            if (files != null) {
                for (File file : files) {
                    processFile(file);
                }
            }
            File[] subDirs = dir.listFiles(File::isDirectory);
            if (subDirs != null) {
                for (File subDir : subDirs) {
                    processDirectory(subDir);
                }
            }
        }
    }

    private static void processFile(File file) throws IOException {
        try (FileInputStream in = new FileInputStream(file)) {
            CompilationUnit cu = StaticJavaParser.parse(in);

            // Apply transformation to handle SnakeYAML 2.0 breaking changes
            SnakeYAMLTransformer transformer = new SnakeYAMLTransformer();
            transformer.visit(cu, null);

            // Save the modified file
            cu.save(file);
        } catch (Exception e) {
            // Skip files that can't be parsed
        }
    }

    static class SnakeYAMLTransformer extends VoidVisitorAdapter<Void> {
        private static final String SNAKEYAML_YAML_CLASS = "org.yaml.snakeyaml.Yaml";
        private static final String SNAKEYAML_DUMPER_OPTIONS_CLASS = "org.yaml.snakeyaml.DumperOptions";
        private static final String SNAKEYAML_LOADER_OPTIONS_CLASS = "org.yaml.snakeyaml.LoaderOptions";
        private static final String SNAKEYAML_BASE_CONSTRUCTOR_CLASS = "org.yaml.snakeyaml.constructor.BaseConstructor";

        @Override
        public void visit(ConstructorInvocationExpr n, Void arg) {
            super.visit(n, arg);

            // Check if this is a Yaml constructor call with old API
            if (n.getType().asString().equals("Yaml")) {
                transformYamlConstructor(n);
            }

            // Check if this is a fully qualified Yaml constructor call
            if (n.getType().asString().equals(SNAKEYAML_YAML_CLASS)) {
                transformYamlConstructor(n);
            }
        }

        private void transformYamlConstructor(ConstructorInvocationExpr n) {
            NodeList<Expression> args = n.getArguments();

            // Pattern 1: Yaml(DumperOptions) -> Yaml(null, null, dumperOptions, null)
            if (args.size() == 1 && args.get(0) instanceof ObjectCreationExpr) {
                ObjectCreationExpr argExpr = (ObjectCreationExpr) args.get(0);
                if (argExpr.getType().asString().equals(SNAKEYAML_DUMPER_OPTIONS_CLASS)) {
                    // Transform Yaml(dumperOptions) to Yaml(null, null, dumperOptions, null)
                    // Create new arguments: null, null, dumperOptions, null
                    NodeList<Expression> newArgs = new NodeList<>();
                    newArgs.add(new NullLiteralExpr());
                    newArgs.add(new NullLiteralExpr());
                    newArgs.add(argExpr);
                    newArgs.add(new NullLiteralExpr());
                    n.setArguments(newArgs);
                }
            }

            // Pattern 2: Yaml(LoaderOptions) -> Yaml(null, null, null, loaderOptions)
            if (args.size() == 1 && args.get(0) instanceof ObjectCreationExpr) {
                ObjectCreationExpr argExpr = (ObjectCreationExpr) args.get(0);
                if (argExpr.getType().asString().equals(SNAKEYAML_LOADER_OPTIONS_CLASS)) {
                    // Transform Yaml(loaderOptions) to Yaml(null, null, null, loaderOptions)
                    // Create new arguments: null, null, null, loaderOptions
                    NodeList<Expression> newArgs = new NodeList<>();
                    newArgs.add(new NullLiteralExpr());
                    newArgs.add(new NullLiteralExpr());
                    newArgs.add(new NullLiteralExpr());
                    newArgs.add(argExpr);
                    n.setArguments(newArgs);
                }
            }

            // Pattern 3: Yaml(constructor) -> Yaml(constructor, null, null, null)
            if (args.size() == 1 && args.get(0) instanceof NameExpr) {
                NameExpr argExpr = (NameExpr) args.get(0);
                // Check if the argument is a BaseConstructor
                if (argExpr.getNameAsString().equals("constructor") || 
                    (argExpr.getScope().isPresent() && 
                     argExpr.getScope().get().toString().equals("constructor"))) {
                    // Transform Yaml(constructor) to Yaml(constructor, null, null, null)
                    // Create new arguments: constructor, null, null, null
                    NodeList<Expression> newArgs = new NodeList<>();
                    newArgs.add(argExpr);
                    newArgs.add(new NullLiteralExpr());
                    newArgs.add(new NullLiteralExpr());
                    newArgs.add(new NullLiteralExpr());
                    n.setArguments(newArgs);
                }
