            if (n.getType().asString().equals("Yaml")) {
                transformYamlConstructor(n);
            }

            // Check if this is a fully qualified Yaml constructor call
            if (n.getType().asString().equals(SNAKEYAML_YAML_CLASS)) {
                transformYamlConstructor(n);
            }
        }

        private void transformYamlConstructor(ConstructorInvocationExpr n) {
            NodeList<Expression> args = n.getArguments();

            // Pattern 1: Yaml(DumperOptions) -> Yaml(null, null, dumperOptions, null)
            if (args.size() == 1 && args.get(0) instanceof ObjectCreationExpr) {
